1	package com.meridian.retail.security;
2	
3	import com.meridian.retail.entity.UsedNonce;
4	import com.meridian.retail.repository.UsedNonceRepository;
5	import jakarta.servlet.FilterChain;
6	import jakarta.servlet.ServletException;
7	import jakarta.servlet.http.HttpServletRequest;
8	import jakarta.servlet.http.HttpServletResponse;
9	import lombok.RequiredArgsConstructor;
10	import lombok.extern.slf4j.Slf4j;
11	import org.springframework.stereotype.Component;
12	import org.springframework.web.filter.OncePerRequestFilter;
13	
14	import java.io.IOException;
15	import java.time.LocalDateTime;
16	
17	/**
18	 * Anti-replay nonce + timestamp validation for privileged POST endpoints.
19	 *
20	 * Applies to: POST /admin/**  AND POST /approval/dual-approve/**.
21	 * Required headers:
22	 *   X-Nonce      — caller-generated unique value (UUID is fine)
23	 *   X-Timestamp  — epoch milliseconds when the request was constructed
24	 *
25	 * Rules:
26	 *   - The timestamp must be within ±5 minutes of server time.
27	 *   - The nonce must not exist in used_nonces (if it does -> replay).
28	 *   - On success the nonce is persisted with expires_at = now + 10 minutes so the same
29	 *     value cannot be reused. A scheduled task (UsedNonceCleanupTask) prunes expired rows.
30	 */
31	@Component
32	@RequiredArgsConstructor
33	@Slf4j
34	public class NonceValidationFilter extends OncePerRequestFilter {
35	
36	    private static final long ALLOWED_SKEW_MS = 5 * 60 * 1000L;
37	    private static final long NONCE_TTL_MINUTES = 10;
38	
39	    private final UsedNonceRepository usedNonceRepository;
40	
41	    @Override
42	    protected void doFilterInternal(HttpServletRequest request,
43	                                    HttpServletResponse response,
44	                                    FilterChain chain) throws ServletException, IOException {
45	
46	        if (!appliesTo(request)) {
47	            chain.doFilter(request, response);
48	            return;
49	        }
50	
51	        String nonce = request.getHeader("X-Nonce");
52	        String timestampStr = request.getHeader("X-Timestamp");
53	
54	        if (nonce == null || nonce.isBlank() || timestampStr == null || timestampStr.isBlank()) {
55	            reject(response, "Missing X-Nonce or X-Timestamp header");
56	            return;
57	        }
58	
59	        long timestamp;
60	        try {
61	            timestamp = Long.parseLong(timestampStr);
62	        } catch (NumberFormatException e) {
63	            reject(response, "Invalid X-Timestamp value");
64	            return;
65	        }
66	
67	        long now = System.currentTimeMillis();
68	        if (Math.abs(now - timestamp) > ALLOWED_SKEW_MS) {
69	            reject(response, "Request timestamp outside allowed window (±5 minutes)");
70	            return;
71	        }
72	
73	        if (usedNonceRepository.existsByNonce(nonce)) {
74	            log.warn("Nonce replay detected: {}", nonce);
75	            reject(response, "Nonce already used (replay)");
76	            return;
77	        }
78	
79	        // Persist as used; expiry slightly longer than the skew so the cleanup job can prune it.
80	        UsedNonce row = UsedNonce.builder()
81	                .nonce(nonce)
82	                .usedAt(LocalDateTime.now())
83	                .expiresAt(LocalDateTime.now().plusMinutes(NONCE_TTL_MINUTES))
84	                .build();
85	        usedNonceRepository.save(row);
86	
87	        chain.doFilter(request, response);
88	    }
89	
90	    private boolean appliesTo(HttpServletRequest request) {
91	        if (!"POST".equalsIgnoreCase(request.getMethod())) return false;
92	        String uri = request.getRequestURI();
93	        return uri.startsWith("/admin/") || uri.startsWith("/approval/dual-approve/");
94	    }
95	
96	    /**
97	     * Narrow browser-form bypass. See SecurityDesignDecisions.md for the full rationale
98	     * and the list of compensating controls.
99	     *
100	     * Only application/x-www-form-urlencoded is exempt. multipart/form-data is NOT:
101	     * there are no admin file-upload forms, so any multipart POST to /admin/** must be
102	     * a programmatic caller and must carry valid X-Nonce / X-Timestamp headers.
103	     */
104	    @Override
105	    protected boolean shouldNotFilter(HttpServletRequest request) {
106	        String uri = request.getRequestURI();
107	        if (uri != null && uri.startsWith("/admin/")) {
108	            String contentType = request.getContentType();
109	            if (contentType != null
110	                    && contentType.toLowerCase().startsWith("application/x-www-form-urlencoded")) {
111	                return true;
112	            }
113	        }
114	        return false;
115	    }
116	
117	    private void reject(HttpServletResponse response, String reason) throws IOException {
118	        response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
119	        response.setContentType("application/json");
120	        response.getWriter().write("{\"error\":\"" + reason + "\"}");
121	    }
122	}
