1	package com.meridian.retail.controller;
2	
3	import com.meridian.retail.entity.ApprovalQueue;
4	import com.meridian.retail.entity.DualApprovalRequest;
5	import com.meridian.retail.entity.RiskLevel;
6	import com.meridian.retail.service.ApprovalService;
7	import com.meridian.retail.service.CampaignValidationException;
8	import com.meridian.retail.service.DualApprovalService;
9	import com.meridian.retail.service.SameApproverException;
10	
11	import java.util.HashMap;
12	import java.util.List;
13	import java.util.Map;
14	import java.util.Optional;
15	import jakarta.servlet.http.HttpServletRequest;
16	import lombok.RequiredArgsConstructor;
17	import org.springframework.security.access.prepost.PreAuthorize;
18	import org.springframework.security.core.Authentication;
19	import org.springframework.stereotype.Controller;
20	import org.springframework.ui.Model;
21	import org.springframework.web.bind.annotation.*;
22	import org.springframework.web.servlet.mvc.support.RedirectAttributes;
23	
24	@Controller
25	@RequestMapping("/approval")
26	@RequiredArgsConstructor
27	@PreAuthorize("hasAnyRole('REVIEWER','ADMIN')")
28	public class ApprovalController {
29	
30	    private final ApprovalService approvalService;
31	    private final DualApprovalService dualApprovalService;
32	
33	    @GetMapping("/queue")
34	    public String queue(Model model) {
35	        model.addAttribute("breadcrumb", "Approval Queue");
36	        List<ApprovalQueue> items = approvalService.listPending();
37	        model.addAttribute("queueItems", items);
38	
39	        // For each HIGH-risk item, side-load the dual-approval row so the template can
40	        // decide whether to render "First Approval" or "Second Approval" and which button
41	        // to disable. Keyed by queueId for easy Thymeleaf lookup.
42	        Map<Long, DualApprovalRequest> dualByQueue = new HashMap<>();
43	        for (ApprovalQueue q : items) {
44	            if (q.getRiskLevel() == RiskLevel.HIGH) {
45	                Optional<DualApprovalRequest> dual = approvalService.findDualRequest(q.getId());
46	                dual.ifPresent(d -> dualByQueue.put(q.getId(), d));
47	            }
48	        }
49	        model.addAttribute("dualByQueue", dualByQueue);
50	        return "approval/queue";
51	    }
52	
53	    /**
54	     * First-approval step for HIGH-risk items. The queue entry stays in REQUIRES_DUAL
55	     * and only flips to APPROVED once the second (different) reviewer completes step two.
56	     */
57	    @PostMapping("/{id}/approve-first")
58	    public String approveFirst(@PathVariable Long id,
59	                               Authentication authentication,
60	                               HttpServletRequest httpRequest,
61	                               RedirectAttributes redirect) {
62	        try {
63	            approvalService.recordFirstApproval(id, authentication.getName(), clientIp(httpRequest));
64	            redirect.addFlashAttribute("successMessage",
65	                    "First approval recorded. A second reviewer must complete the dual approval.");
66	        } catch (SameApproverException | CampaignValidationException e) {
67	            redirect.addFlashAttribute("errorMessage", e.getMessage());
68	        }
69	        return "redirect:/approval/queue";
70	    }
71	
72	    /**
73	     * Second (completing) approval step for HIGH-risk items. The service enforces
74	     * approver1 != approver2 — a user who recorded the first approval will be rejected
75	     * here with SameApproverException.
76	     */
77	    @PostMapping("/{id}/approve-second")
78	    public String approveSecond(@PathVariable Long id,
79	                                @RequestParam(required = false) String notes,
80	                                Authentication authentication,
81	                                HttpServletRequest httpRequest,
82	                                RedirectAttributes redirect) {
83	        try {
84	            approvalService.recordSecondApproval(id, authentication.getName(), notes, clientIp(httpRequest));
85	            redirect.addFlashAttribute("successMessage", "Dual approval complete — campaign approved.");
86	        } catch (SameApproverException | CampaignValidationException e) {
87	            redirect.addFlashAttribute("errorMessage", e.getMessage());
88	        }
89	        return "redirect:/approval/queue";
90	    }
91	
92	    @PostMapping("/{id}/approve")
93	    public String approve(@PathVariable Long id,
94	                          @RequestParam(required = false) String notes,
95	                          Authentication authentication,
96	                          HttpServletRequest httpRequest,
97	                          RedirectAttributes redirect) {
98	        try {
99	            approvalService.approve(id, authentication.getName(), notes, clientIp(httpRequest));
100	            redirect.addFlashAttribute("successMessage", "Approval recorded.");
101	        } catch (SameApproverException | CampaignValidationException e) {
102	            redirect.addFlashAttribute("errorMessage", e.getMessage());
103	        }
104	        return "redirect:/approval/queue";
105	    }
106	
107	    @PostMapping("/{id}/reject")
108	    public String reject(@PathVariable Long id,
109	                         @RequestParam(required = false) String notes,
110	                         Authentication authentication,
111	                         HttpServletRequest httpRequest,
112	                         RedirectAttributes redirect) {
113	        try {
114	            approvalService.reject(id, authentication.getName(), notes, clientIp(httpRequest));
115	            redirect.addFlashAttribute("successMessage", "Rejection recorded.");
116	        } catch (SameApproverException | CampaignValidationException e) {
117	            redirect.addFlashAttribute("errorMessage", e.getMessage());
118	        }
119	        return "redirect:/approval/queue";
120	    }
121	
122	    /**
123	     * Dual-approval second step. The NonceValidationFilter intercepts this URL and
124	     * requires X-Nonce + X-Timestamp headers (anti-replay).
125	     */
126	    @PostMapping("/dual-approve/{requestId}")
127	    public String dualApprove(@PathVariable Long requestId,
128	                              Authentication authentication,
129	                              HttpServletRequest httpRequest,
130	                              RedirectAttributes redirect) {
131	        try {
132	            dualApprovalService.recordSecond(requestId, authentication.getName(), clientIp(httpRequest));
133	            redirect.addFlashAttribute("successMessage", "Dual approval complete.");
134	        } catch (SameApproverException | CampaignValidationException e) {
135	            redirect.addFlashAttribute("errorMessage", e.getMessage());
136	        }
137	        return "redirect:/approval/queue";
138	    }
139	
140	    private String clientIp(HttpServletRequest request) {
141	        String header = request.getHeader("X-Forwarded-For");
142	        if (header != null && !header.isBlank()) return header.split(",")[0].trim();
143	        return request.getRemoteAddr();
144	    }
145	}
