1	package com.meridian.retail.service;
2	
3	import com.meridian.retail.audit.AuditAction;
4	import com.meridian.retail.audit.AuditLogService;
5	import com.meridian.retail.dto.CouponDTO;
6	import com.meridian.retail.dto.CreateCouponRequest;
7	import com.meridian.retail.entity.Coupon;
8	import com.meridian.retail.repository.CouponRepository;
9	import com.meridian.retail.security.XssInputSanitizer;
10	import lombok.RequiredArgsConstructor;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.math.BigDecimal;
15	import java.util.HashSet;
16	import java.util.List;
17	import java.util.Set;
18	
19	@Service
20	@RequiredArgsConstructor
21	public class CouponService {
22	
23	    private final CouponRepository couponRepository;
24	    private final CampaignService campaignService;
25	    private final AuditLogService auditLogService;
26	
27	    public List<Coupon> listByCampaign(Long campaignId) {
28	        return couponRepository.findByCampaignId(campaignId);
29	    }
30	
31	    public List<Coupon> listAll() {
32	        return couponRepository.findAll();
33	    }
34	
35	    public Coupon findById(Long id) {
36	        return couponRepository.findById(id)
37	                .orElseThrow(() -> new CampaignValidationException("Coupon not found: " + id));
38	    }
39	
40	    /**
41	     * Update a coupon. The code itself is immutable (it can be referenced from live
42	     * receipts / redemption logs); only discount value, limits, dates, and stacking
43	     * rules can be modified. An AuditLog row is written with before/after state.
44	     */
45	    @Transactional
46	    public Coupon updateCoupon(Long id, CreateCouponRequest req, String username, String ipAddress) {
47	        Coupon existing = findById(id);
48	        CouponDTO before = CouponDTO.from(existing);
49	
50	        campaignService.validateDiscountValue(req.getDiscountType(), req.getDiscountValue());
51	
52	        existing.setDiscountType(req.getDiscountType());
53	        existing.setDiscountValue(req.getDiscountValue());
54	        existing.setMinPurchaseAmount(req.getMinPurchaseAmount() != null ? req.getMinPurchaseAmount() : BigDecimal.ZERO);
55	        existing.setMaxUses(req.getMaxUses());
56	        existing.setStackable(req.isStackable());
57	        existing.setMutualExclusionGroup(XssInputSanitizer.sanitize(req.getMutualExclusionGroup()));
58	        existing.setValidFrom(req.getValidFrom());
59	        existing.setValidUntil(req.getValidUntil());
60	
61	        Coupon saved = couponRepository.save(existing);
62	        auditLogService.log(AuditAction.COUPON_UPDATED, "Coupon", saved.getId(),
63	                before, CouponDTO.from(saved), username, ipAddress);
64	        return saved;
65	    }
66	
67	    @Transactional
68	    public Coupon createCoupon(CreateCouponRequest req, String username, String ipAddress) {
69	        // Sanitize then validate
70	        String code = XssInputSanitizer.sanitize(req.getCode());
71	        if (code == null || code.isBlank()) {
72	            throw new CampaignValidationException("Coupon code is required");
73	        }
74	        if (couponRepository.existsByCodeIgnoreCase(code)) {
75	            throw new CampaignValidationException("Coupon code already in use: " + code);
76	        }
77	        // Defer to CampaignService for the discount value rule so it stays consistent.
78	        campaignService.validateDiscountValue(req.getDiscountType(), req.getDiscountValue());
79	
80	        Coupon c = Coupon.builder()
81	                .campaignId(req.getCampaignId())
82	                .code(code)
83	                .discountType(req.getDiscountType())
84	                .discountValue(req.getDiscountValue())
85	                .minPurchaseAmount(req.getMinPurchaseAmount() != null ? req.getMinPurchaseAmount() : BigDecimal.ZERO)
86	                .maxUses(req.getMaxUses())
87	                .stackable(req.isStackable())
88	                .mutualExclusionGroup(XssInputSanitizer.sanitize(req.getMutualExclusionGroup()))
89	                .validFrom(req.getValidFrom())
90	                .validUntil(req.getValidUntil())
91	                .build();
92	
93	        Coupon saved = couponRepository.save(c);
94	        auditLogService.log(AuditAction.COUPON_CREATED, "Coupon", saved.getId(),
95	                null, CouponDTO.from(saved), username, ipAddress);
96	        return saved;
97	    }
98	
99	    public boolean isCodeAvailable(String code) {
100	        if (code == null || code.isBlank()) return false;
101	        return !couponRepository.existsByCodeIgnoreCase(code);
102	    }
103	
104	    /**
105	     * Returns true if {@code candidate} can be combined with the supplied set of already-applied
106	     * coupon ids. Rules:
107	     *   - If the candidate is non-stackable AND the cart already has any coupon, reject.
108	     *   - If any existing coupon shares the candidate's mutual_exclusion_group, reject.
109	     */
110	    public boolean checkStackingCompatibility(Coupon candidate, List<Long> existingCouponIds) {
111	        if (candidate == null) return false;
112	        List<Coupon> existing = couponRepository.findAllById(existingCouponIds);
113	
114	        if (!candidate.isStackable() && !existing.isEmpty()) {
115	            return false;
116	        }
117	        for (Coupon e : existing) {
118	            if (!e.isStackable()) return false;
119	        }
120	
121	        Set<String> groups = new HashSet<>();
122	        if (candidate.getMutualExclusionGroup() != null) groups.add(candidate.getMutualExclusionGroup());
123	        for (Coupon e : existing) {
124	            if (e.getMutualExclusionGroup() != null && !groups.add(e.getMutualExclusionGroup())) {
125	                // Already present -> two coupons share an exclusion group -> reject.
126	                return false;
127	            }
128	        }
129	        // Also reject if candidate's group is already used by an existing coupon.
130	        if (candidate.getMutualExclusionGroup() != null) {
131	            for (Coupon e : existing) {
132	                if (candidate.getMutualExclusionGroup().equalsIgnoreCase(e.getMutualExclusionGroup())) {
133	                    return false;
134	                }
135	            }
136	        }
137	        return true;
138	    }
139	}
