47	    /**
48	     * Campaign-level performance ranking (requirement: "top performing campaigns by
49	     * store and date range"). Unlike getTopCampaigns — which is actually coupon-centric —
50	     * this rolls redemptions up to the parent campaign via the coupon → campaign join.
51	     */
52	    public List<CampaignMetric> getTopCampaignsByCampaign(String storeId, LocalDateTime from,
53	                                                          LocalDateTime to, int limit) {
54	        List<Object[]> rows = redemptionRepository.topCampaignsByRedemptions(storeId, from, to);
55	        List<CampaignMetric> out = new ArrayList<>();
