1	package com.meridian.retail.backup;
2	
3	import com.meridian.retail.audit.AuditAction;
4	import com.meridian.retail.audit.AuditLogService;
5	import com.meridian.retail.entity.BackupRecord;
6	import com.meridian.retail.entity.BackupStatus;
7	import com.meridian.retail.repository.BackupRecordRepository;
8	import lombok.RequiredArgsConstructor;
9	import lombok.extern.slf4j.Slf4j;
10	import org.springframework.beans.factory.annotation.Value;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.io.IOException;
15	import java.nio.file.Files;
16	import java.nio.file.Path;
17	import java.nio.file.Paths;
18	import java.time.Duration;
19	import java.time.LocalDateTime;
20	import java.util.Map;
21	
22	/**
23	 * Restore workflow for disaster recovery drills. Pairs with {@link BackupService}.
24	 *
25	 * Two entry points:
26	 *   - restoreFromBackup(id) — overwrites the live database from a specific backup row.
27	 *     Intended for real DR scenarios, invoked from /admin/backup/{id}/restore.
28	 *   - testRestoreLatest() — "does the latest backup actually deserialize?" drill. Gunzips
29	 *     the file into a temporary location and verifies it parses, without touching the
30	 *     live DB. Invoked from /admin/backup/test-restore and from the weekly scheduler.
31	 *
32	 * Both paths update {@code BackupRecord.restoredAt} and emit audit log entries via
33	 * {@link AuditLogService}. The mysql command is built with the same
34	 * MYSQL_PWD-env-var pattern from HIGH #5 — the DB password never appears in process args.
35	 */
36	@Service
37	@RequiredArgsConstructor
38	@Slf4j
39	public class RestoreService {
40	
41	    @Value("${spring.datasource.url:}")
42	    private String datasourceUrl;
43	
44	    @Value("${spring.datasource.username:retail_user}")
45	    private String datasourceUsername;
46	
47	    @Value("${spring.datasource.password:retail_pass}")
48	    private String datasourcePassword;
49	
50	    private final BackupRecordRepository backupRecordRepository;
51	    private final AuditLogService auditLogService;
52	
53	    public record RestoreResult(boolean success, long durationMs, String message, Long backupId) {}
54	
55	    /**
56	     * Full restore into the live DB. Should only be used during actual DR. The caller
57	     * is expected to have already put the app into maintenance mode.
58	     */
59	    @Transactional
60	    public RestoreResult restoreFromBackup(Long backupId, String operator, String ipAddress) {
61	        BackupRecord rec = backupRecordRepository.findById(backupId)
62	                .orElseThrow(() -> new IllegalArgumentException("Backup not found: " + backupId));
63	        if (rec.getStatus() != BackupStatus.COMPLETE) {
64	            return markAndReturn(rec, false, 0L, "Backup is not COMPLETE", operator, ipAddress);
65	        }
66	
67	        Path backupFile = Paths.get(rec.getFilePath());
68	        if (!Files.exists(backupFile)) {
69	            return markAndReturn(rec, false, 0L, "Backup file missing on disk", operator, ipAddress);
70	        }
71	
72	        long start = System.currentTimeMillis();
73	        try {
74	            Path rawSql = gunzipToTemp(backupFile);
75	            try {
76	                int exit = runMysqlClient(rawSql, extractDbName(datasourceUrl));
77	                long duration = System.currentTimeMillis() - start;
78	                boolean ok = exit == 0;
79	                return markAndReturn(rec, ok, duration,
80	                        ok ? "Restore completed in " + Duration.ofMillis(duration)
81	                           : "mysql exited with code " + exit,
82	                        operator, ipAddress);
83	            } finally {
84	                try { Files.deleteIfExists(rawSql); } catch (IOException ignored) { }
85	            }
86	        } catch (Exception e) {
87	            long duration = System.currentTimeMillis() - start;
88	            log.error("Restore from backup {} failed", backupId, e);
89	            return markAndReturn(rec, false, duration, "Exception: " + e.getMessage(), operator, ipAddress);
90	        }
91	    }
92	
93	    /**
94	     * Restore drill: verify that the latest COMPLETE backup gunzips cleanly and
95	     * contains at least one expected SQL statement. Does NOT touch the live DB —
96	     * safe to run on a schedule. Updates restoredAt on success so the admin page
97	     * shows the last drill timestamp.
98	     */
99	    @Transactional
100	    public RestoreResult testRestoreLatest(String operator, String ipAddress) {
101	        BackupRecord latest = backupRecordRepository
102	                .findTop1ByStatusOrderByCreatedAtDesc(BackupStatus.COMPLETE)
103	                .orElse(null);
104	        if (latest == null) {
105	            return new RestoreResult(false, 0L, "No COMPLETE backup available", null);
106	        }
107	        Path backupFile = Paths.get(latest.getFilePath());
108	        if (!Files.exists(backupFile)) {
109	            return markAndReturn(latest, false, 0L, "Backup file missing on disk", operator, ipAddress);
110	        }
111	
112	        long start = System.currentTimeMillis();
113	        try {
114	            Path rawSql = gunzipToTemp(backupFile);
115	            try {
116	                long size = Files.size(rawSql);
117	                String head = Files.readString(rawSql.getFileSystem().getPath(rawSql.toString()),
118	                        java.nio.charset.StandardCharsets.UTF_8).lines().limit(5)
119	                        .reduce("", (a, b) -> a + b + "\n");
120	                boolean looksLikeDump = head.contains("MySQL") || head.contains("CREATE")
121	                        || head.contains("INSERT") || head.contains("-- ");
122	                long duration = System.currentTimeMillis() - start;
123	                if (size > 0 && looksLikeDump) {
124	                    return markAndReturn(latest, true, duration,
125	                            "Test-restore OK: " + size + " bytes of SQL parsed", operator, ipAddress);
126	                }
127	                return markAndReturn(latest, false, duration,
128	                        "Test-restore failed: file does not look like a MySQL dump", operator, ipAddress);
129	            } finally {
130	                try { Files.deleteIfExists(rawSql); } catch (IOException ignored) { }
131	            }
132	        } catch (Exception e) {
133	            long duration = System.currentTimeMillis() - start;
134	            log.error("Test-restore of backup {} failed", latest.getId(), e);
135	            return markAndReturn(latest, false, duration, "Exception: " + e.getMessage(), operator, ipAddress);
136	        }
137	    }
138	
139	    private RestoreResult markAndReturn(BackupRecord rec, boolean success, long durationMs,
140	                                        String message, String operator, String ipAddress) {
141	        if (success) {
142	            rec.setRestoredAt(LocalDateTime.now());
143	            backupRecordRepository.save(rec);
144	        }
145	        auditLogService.log(AuditAction.BACKUP_RUN, "BackupRecord", rec.getId(),
146	                null, Map.of("operation", "RESTORE",
147	                             "success", success,
148	                             "durationMs", durationMs,
149	                             "message", message),
150	                operator, ipAddress);
151	        return new RestoreResult(success, durationMs, message, rec.getId());
152	    }
153	
154	    private Path gunzipToTemp(Path gzFile) throws IOException {
155	        Path tempDir = gzFile.getParent();
156	        Path out = Files.createTempFile(tempDir, "restore_", ".sql");
157	        try (var in = new java.util.zip.GZIPInputStream(Files.newInputStream(gzFile));
158	             var os = Files.newOutputStream(out)) {
159	            byte[] buf = new byte[16 * 1024];
160	            int n;
161	            while ((n = in.read(buf)) > 0) os.write(buf, 0, n);
162	        }
163	        return out;
164	    }
165	
166	    /**
167	     * Execute the mysql client against the raw SQL file. Same MYSQL_PWD safety pattern
168	     * as BackupService.buildMysqldumpCommand — no password in argv.
169	     */
170	    private int runMysqlClient(Path sqlFile, String dbName) throws IOException, InterruptedException {
171	        ProcessBuilder pb = new ProcessBuilder(
172	                "mysql",
173	                "-h", extractDbHost(datasourceUrl),
174	                "-u", datasourceUsername,
175	                dbName);
176	        pb.environment().put("MYSQL_PWD", datasourcePassword);
177	        pb.redirectInput(sqlFile.toFile());
178	        pb.redirectErrorStream(true);
179	        Process p = pb.start();
180	        return p.waitFor();
181	    }
182	
183	    private String extractDbName(String url) {
184	        if (url == null || !url.contains("/")) return "retail_campaign";
185	        String s = url.substring(url.lastIndexOf('/') + 1);
186	        int q = s.indexOf('?');
187	        return q < 0 ? s : s.substring(0, q);
188	    }
189	
190	    private String extractDbHost(String url) {
191	        if (url == null) return "localhost";
192	        int start = url.indexOf("//");
193	        if (start < 0) return "localhost";
194	        String rest = url.substring(start + 2);
195	        int slash = rest.indexOf('/');
196	        String hostPort = slash < 0 ? rest : rest.substring(0, slash);
197	        int colon = hostPort.indexOf(':');
198	        return colon < 0 ? hostPort : hostPort.substring(0, colon);
199	    }
200	}
