1	package com.meridian.retail.service;
2	
3	import com.meridian.retail.audit.AuditAction;
4	import com.meridian.retail.audit.AuditLogService;
5	import com.meridian.retail.entity.ApprovalQueue;
6	import com.meridian.retail.entity.ApprovalStatus;
7	import com.meridian.retail.entity.Campaign;
8	import com.meridian.retail.entity.CampaignStatus;
9	import com.meridian.retail.entity.RiskLevel;
10	import com.meridian.retail.repository.ApprovalQueueRepository;
11	import com.meridian.retail.repository.CampaignRepository;
12	import com.meridian.retail.security.XssInputSanitizer;
13	import lombok.RequiredArgsConstructor;
14	import lombok.extern.slf4j.Slf4j;
15	import org.springframework.stereotype.Service;
16	import org.springframework.transaction.annotation.Transactional;
17	
18	import java.util.List;
19	import java.util.Optional;
20	
21	/**
22	 * Approval queue lifecycle: submit -> assign -> approve|reject. HIGH risk items
23	 * require two-eyes via DualApprovalService — see {@link #approve(Long, String, String, String)}.
24	 */
25	@Service
26	@RequiredArgsConstructor
27	@Slf4j
28	public class ApprovalService {
29	
30	    private final ApprovalQueueRepository approvalQueueRepository;
31	    private final CampaignRepository campaignRepository;
32	    private final DualApprovalService dualApprovalService;
33	    private final AuditLogService auditLogService;
34	
35	    /**
36	     * Queue view for reviewers: both single-approval PENDING items AND HIGH-risk items
37	     * still waiting for dual sign-off (REQUIRES_DUAL). If we filtered on PENDING only,
38	     * every HIGH-risk campaign would disappear from the UI the moment it was submitted
39	     * and the dual-approval workflow would be unreachable.
40	     */
41	    public List<ApprovalQueue> listPending() {
42	        return approvalQueueRepository.findByStatusInOrderByCreatedAtAsc(
43	                List.of(ApprovalStatus.PENDING, ApprovalStatus.REQUIRES_DUAL));
44	    }
45	
46	    /** Look up the dual-approval row that backs a queue entry (may not exist for LOW/MED items). */
47	    public Optional<com.meridian.retail.entity.DualApprovalRequest> findDualRequest(Long queueId) {
48	        return dualApprovalService.findByQueueId(queueId);
49	    }
50	
51	    public ApprovalQueue findById(Long id) {
52	        return approvalQueueRepository.findById(id)
53	                .orElseThrow(() -> new CampaignValidationException("Approval queue entry not found: " + id));
54	    }
55	
56	    @Transactional
57	    public ApprovalQueue submitToQueue(Long campaignId, String requestedBy, RiskLevel riskLevel, String ipAddress) {
58	        Campaign c = campaignRepository.findById(campaignId)
59	                .orElseThrow(() -> new CampaignValidationException("Campaign not found: " + campaignId));
60	        ApprovalQueue q = ApprovalQueue.builder()
61	                .campaignId(c.getId())
62	                .requestedBy(requestedBy)
63	                .status(riskLevel == RiskLevel.HIGH ? ApprovalStatus.REQUIRES_DUAL : ApprovalStatus.PENDING)
64	                .riskLevel(riskLevel)
65	                .build();
66	        ApprovalQueue saved = approvalQueueRepository.save(q);
67	        if (riskLevel == RiskLevel.HIGH) {
68	            dualApprovalService.initiate(saved.getId());
69	        }
70	        auditLogService.log(AuditAction.APPROVAL_SUBMITTED, "ApprovalQueue", saved.getId(),
71	                null, saved, requestedBy, ipAddress);
72	        return saved;
73	    }
74	
75	    /**
76	     * Record the FIRST of two required approvals for a HIGH-risk queue entry. The row
77	     * remains in REQUIRES_DUAL — it only flips to APPROVED once recordSecondApproval()
78	     * runs with a DIFFERENT user.
79	     */
80	    @Transactional
81	    public ApprovalQueue recordFirstApproval(Long queueId, String reviewerUsername, String ipAddress) {
82	        ApprovalQueue q = findById(queueId);
83	        if (q.getRiskLevel() != RiskLevel.HIGH) {
84	            throw new CampaignValidationException("First-approval step only applies to HIGH risk items");
85	        }
86	        if (q.getRequestedBy() != null && q.getRequestedBy().equalsIgnoreCase(reviewerUsername)) {
87	            throw new SameApproverException("A reviewer cannot approve a campaign they themselves submitted");
88	        }
89	        dualApprovalService.recordFirstForQueue(q.getId(), reviewerUsername, ipAddress);
90	        q.setStatus(ApprovalStatus.REQUIRES_DUAL);
91	        q.setAssignedReviewer(reviewerUsername);
92	        return approvalQueueRepository.save(q);
93	    }
94	
95	    /**
96	     * Record the SECOND approval and, when successful, finalize the queue entry to APPROVED
97	     * and cascade to the underlying campaign. Throws SameApproverException if the same user
98	     * attempts to fulfil both halves.
99	     */
100	    @Transactional
101	    public ApprovalQueue recordSecondApproval(Long queueId, String reviewerUsername, String notes, String ipAddress) {
102	        ApprovalQueue q = findById(queueId);
103	        if (q.getRiskLevel() != RiskLevel.HIGH) {
104	            throw new CampaignValidationException("Second-approval step only applies to HIGH risk items");
105	        }
106	        if (q.getRequestedBy() != null && q.getRequestedBy().equalsIgnoreCase(reviewerUsername)) {
107	            throw new SameApproverException("A reviewer cannot approve a campaign they themselves submitted");
108	        }
109	        // This will throw SameApproverException if the two approvers match (two-eyes rule)
110	        // and CampaignValidationException if the first approval has not yet been recorded.
111	        dualApprovalService.recordSecondForQueue(q.getId(), reviewerUsername, ipAddress);
112	
113	        q.setStatus(ApprovalStatus.APPROVED);
114	        q.setNotes(XssInputSanitizer.sanitize(notes));
115	        q.setAssignedReviewer(reviewerUsername);
116	        ApprovalQueue saved = approvalQueueRepository.save(q);
117	
118	        campaignRepository.findById(q.getCampaignId()).ifPresent(c -> {
119	            c.setStatus(CampaignStatus.APPROVED);
120	            campaignRepository.save(c);
121	        });
122	
123	        auditLogService.log(AuditAction.APPROVAL_APPROVED, "ApprovalQueue", saved.getId(),
124	                null, saved, reviewerUsername, ipAddress);
125	        return saved;
126	    }
127	
128	    @Transactional
129	    public ApprovalQueue assign(Long queueId, String reviewerUsername) {
130	        ApprovalQueue q = findById(queueId);
131	        q.setAssignedReviewer(reviewerUsername);
132	        return approvalQueueRepository.save(q);
133	    }
134	
135	    /**
136	     * Approve a pending entry.
137	     *
138	     * Object-level rule: a reviewer cannot approve their own submission. We compare
139	     * requestedBy vs reviewerUsername case-insensitively and throw SameApproverException
140	     * if they match. This is enforced HERE in the service, not in the controller, so the
141	     * rule is honoured no matter what UI calls this method.
142	     */
143	    @Transactional
144	    public ApprovalQueue approve(Long queueId, String reviewerUsername, String notes, String ipAddress) {
145	        ApprovalQueue q = findById(queueId);
146	
147	        if (q.getRequestedBy() != null && q.getRequestedBy().equalsIgnoreCase(reviewerUsername)) {
148	            throw new SameApproverException("A reviewer cannot approve a campaign they themselves submitted");
149	        }
150	
151	        if (q.getRiskLevel() == RiskLevel.HIGH) {
152	            // For HIGH risk we require dual approval to be COMPLETE before flipping the status.
153	            // IMPORTANT: a single reviewer hitting "approve" must NEVER satisfy this —
154	            // we only consult the persisted dual-approval row, which tracks two distinct users.
155	            com.meridian.retail.entity.DualApprovalRequest dual =
156	                    dualApprovalService.initiate(q.getId());
157	            boolean ready = dualApprovalService.isComplete(dual.getId());
158	            if (!ready) {
159	                log.info("HIGH risk approval still requires dual sign-off: queueId={}", queueId);
160	                q.setStatus(ApprovalStatus.REQUIRES_DUAL);
161	                q.setNotes(XssInputSanitizer.sanitize(notes));
162	                q.setAssignedReviewer(reviewerUsername);
163	                approvalQueueRepository.save(q);
164	                return q;
165	            }
166	        }
167	
168	        q.setStatus(ApprovalStatus.APPROVED);
169	        q.setNotes(XssInputSanitizer.sanitize(notes));
170	        q.setAssignedReviewer(reviewerUsername);
171	        ApprovalQueue saved = approvalQueueRepository.save(q);
172	
173	        // Cascade: bump the campaign's status to APPROVED so it can later be published.
174	        campaignRepository.findById(q.getCampaignId()).ifPresent(c -> {
175	            c.setStatus(CampaignStatus.APPROVED);
176	            campaignRepository.save(c);
177	        });
178	
179	        auditLogService.log(AuditAction.APPROVAL_APPROVED, "ApprovalQueue", saved.getId(),
180	                null, saved, reviewerUsername, ipAddress);
181	        return saved;
182	    }
183	
184	    @Transactional
185	    public ApprovalQueue reject(Long queueId, String reviewerUsername, String notes, String ipAddress) {
186	        ApprovalQueue q = findById(queueId);
187	
188	        if (q.getRequestedBy() != null && q.getRequestedBy().equalsIgnoreCase(reviewerUsername)) {
189	            throw new SameApproverException("A reviewer cannot reject a campaign they themselves submitted");
190	        }
191	
192	        q.setStatus(ApprovalStatus.REJECTED);
193	        q.setNotes(XssInputSanitizer.sanitize(notes));
194	        q.setAssignedReviewer(reviewerUsername);
195	        ApprovalQueue saved = approvalQueueRepository.save(q);
196	
197	        campaignRepository.findById(q.getCampaignId()).ifPresent(c -> {
198	            c.setStatus(CampaignStatus.REJECTED);
199	            campaignRepository.save(c);
200	        });
201	
202	        auditLogService.log(AuditAction.APPROVAL_REJECTED, "ApprovalQueue", saved.getId(),
203	                null, saved, reviewerUsername, ipAddress);
204	        return saved;
205	    }
206	}
