25	/**
26	 * Nightly local MySQL backup via mysqldump + gzip.
27	 *
28	 * Scheduled at 02:00 server time. Manually triggerable from /admin/backup/run.
29	 *
30	 * Recovery procedure (also documented in README.md):
31	 *   1. docker compose down
32	 *   2. Locate the latest .sql.gz under /app/backups/
33	 *   3. docker compose up mysql
34	 *   4. gunzip < backup.sql.gz | docker exec -i mysql mysql -uretail_user -pretail_pass retail_campaign
35	 *   5. docker compose up app
36	 *
37	 * Retention: files older than {@code app.backup.retention-days} (default 14) are deleted
38	 * from disk and their BackupRecord rows are flipped to status=DELETED.
39	 */
40	@Service
41	@RequiredArgsConstructor
42	@Slf4j
43	public class BackupService {
44	
45	    @Value("${app.backup.path:/app/backups}")
46	    private String backupPath;
47	
48	    @Value("${app.backup.retention-days:14}")
49	    private int retentionDays;
50	
51	    @Value("${spring.datasource.url:}")
52	    private String datasourceUrl;
53	
54	    @Value("${spring.datasource.username:retail_user}")
55	    private String datasourceUsername;
56	
57	    @Value("${spring.datasource.password:retail_pass}")
58	    private String datasourcePassword;
59	
60	    private final BackupRecordRepository backupRecordRepository;
61	    private final AuditLogService auditLogService;
62	
63	    /** Nightly cron at 02:00 server time. */
64	    @Scheduled(cron = "0 0 2 * * *")
65	    @Transactional
66	    public BackupRecord runNightlyBackup() {
67	        return runBackup("scheduled");
68	    }
69	
70	    /** Manual trigger from the admin UI. */
71	    @Transactional
72	    public BackupRecord runManualBackup(String operatorUsername, String ipAddress) {
73	        BackupRecord r = runBackup(operatorUsername == null ? "admin" : operatorUsername);
74	        auditLogService.log(AuditAction.BACKUP_RUN, "BackupRecord", r.getId(),
75	                null, java.util.Map.of("filename", r.getFilename(), "status", r.getStatus().name()),
76	                operatorUsername, ipAddress);
77	        return r;
78	    }
79	
80	    private BackupRecord runBackup(String operator) {
81	        try {
82	            Path dir = Paths.get(backupPath);
83	            if (!Files.exists(dir)) Files.createDirectories(dir);
84	
85	            String filename = "backup_" + LocalDate.now() + "_" + System.currentTimeMillis() + ".sql.gz";
86	            Path target = dir.resolve(filename);
87	
88	            String dbName = extractDbName(datasourceUrl);
89	            String dbHost = extractDbHost(datasourceUrl);
90	
91	            // HIGH #5 fix: DB password must NEVER appear in process arguments
92	            // (visible via /proc/*/cmdline, process list, shell history). Pass it
93	            // through the MYSQL_PWD environment variable instead. mysqldump itself
94	            // can then write directly to the target via --result-file, and we gzip
95	            // the result in Java to avoid /bin/sh -c string interpolation.
96	            Path rawSql = Files.createTempFile(dir, "backup_raw_", ".sql");
97	            ProcessBuilder pb = new ProcessBuilder(
98	                    "mysqldump",
99	                    "-h", dbHost,
100	                    "-u", datasourceUsername,
101	                    "--result-file=" + rawSql.toAbsolutePath(),
102	                    dbName);
103	            pb.environment().put("MYSQL_PWD", datasourcePassword);
104	            pb.redirectErrorStream(true);
105	            Process p = pb.start();
106	            int exit = p.waitFor();
107	
108	            // Gzip the raw dump into the target file, then delete the plaintext temp.
109	            if (exit == 0 && Files.exists(rawSql)) {
110	                try (var in = Files.newInputStream(rawSql);
111	                     var out = Files.newOutputStream(target);
112	                     var gzip = new java.util.zip.GZIPOutputStream(out)) {
113	                    byte[] buf = new byte[16 * 1024];
114	                    int n;
115	                    while ((n = in.read(buf)) > 0) gzip.write(buf, 0, n);
116	                }
117	            }
118	            try { Files.deleteIfExists(rawSql); } catch (IOException ignored) { }
119	
120	            BackupStatus status = (exit == 0 && Files.exists(target) && Files.size(target) > 0)
121	                    ? BackupStatus.COMPLETE
122	                    : BackupStatus.FAILED;
123	
124	            long size = Files.exists(target) ? Files.size(target) : 0;
125	            String sha256 = (status == BackupStatus.COMPLETE) ? sha256Hex(target) : null;
126	
127	            BackupRecord rec = BackupRecord.builder()
128	                    .filename(filename)
129	                    .filePath(target.toString())
130	                    .fileSizeBytes(size)
131	                    .sha256Checksum(sha256)
132	                    .status(status)
133	                    .notes("Initiated by " + operator + ", exit=" + exit)
134	                    .build();
135	            BackupRecord saved = backupRecordRepository.save(rec);
136	
137	            // Retention sweep
138	            pruneExpired();
139	            return saved;
140	        } catch (Exception e) {
141	            log.error("Backup failed: {}", e.getMessage(), e);
142	            BackupRecord rec = BackupRecord.builder()
143	                    .filename("backup_failed_" + System.currentTimeMillis())
144	                    .filePath("")
145	                    .fileSizeBytes(0)
146	                    .status(BackupStatus.FAILED)
147	                    .notes("Exception: " + e.getMessage())
148	                    .build();
149	            return backupRecordRepository.save(rec);
150	        }
151	    }
152	
153	    /**
154	     * Visible-for-tests: construct the mysqldump ProcessBuilder without executing it.
155	     * Lets BackupCommandSafetyTest assert the password is NEVER in the argument list.
156	     */
157	    public static ProcessBuilder buildMysqldumpCommand(String dbHost, String dbUser,
158	                                                       String dbPassword, String dbName,
159	                                                       Path resultFile) {
160	        ProcessBuilder pb = new ProcessBuilder(
161	                "mysqldump",
162	                "-h", dbHost,
163	                "-u", dbUser,
164	                "--result-file=" + resultFile.toAbsolutePath(),
165	                dbName);
166	        pb.environment().put("MYSQL_PWD", dbPassword);
167	        return pb;
168	    }
169	
170	    private void pruneExpired() {
171	        LocalDateTime cutoff = LocalDateTime.now().minusDays(retentionDays);
172	        List<BackupRecord> stale = backupRecordRepository.findByStatusAndCreatedAtBefore(BackupStatus.COMPLETE, cutoff);
173	        for (BackupRecord r : stale) {
174	            try {
175	                Files.deleteIfExists(Paths.get(r.getFilePath()));
176	            } catch (IOException e) {
177	                log.warn("Failed to delete expired backup {}: {}", r.getFilePath(), e.getMessage());
178	            }
179	            r.setStatus(BackupStatus.DELETED);
180	            backupRecordRepository.save(r);
181	        }
182	    }
183	
184	    private String extractDbName(String url) {
185	        if (url == null || !url.contains("/")) return "retail_campaign";
186	        String s = url.substring(url.lastIndexOf('/') + 1);
187	        int q = s.indexOf('?');
188	        return q < 0 ? s : s.substring(0, q);
189	    }
190	
191	    private String extractDbHost(String url) {
192	        if (url == null) return "localhost";
193	        // jdbc:mysql://host:port/db?...
194	        int start = url.indexOf("//");
195	        if (start < 0) return "localhost";
196	        String rest = url.substring(start + 2);
197	        int slash = rest.indexOf('/');
198	        String hostPort = slash < 0 ? rest : rest.substring(0, slash);
199	        int colon = hostPort.indexOf(':');
200	        return colon < 0 ? hostPort : hostPort.substring(0, colon);
201	    }
202	
203	    private String sha256Hex(Path path) {
204	        try (var in = Files.newInputStream(path)) {
205	            MessageDigest md = MessageDigest.getInstance("SHA-256");
206	            byte[] buf = new byte[8192];
207	            int n;
208	            while ((n = in.read(buf)) > 0) md.update(buf, 0, n);
209	            return HexFormat.of().formatHex(md.digest());
210	        } catch (Exception e) {
211	            return null;
212	        }
213	    }
214	}
