            log.error("Weekly restore drill threw an exception", e);
            auditLogService.log(AuditAction.BACKUP_RUN, "BackupRecord", null,
                    null, Map.of("operation", "RESTORE_DRILL",
                                 "success", false,
                                 "error", String.valueOf(e.getMessage())),
                    "system", "scheduler");
        }
    }

