1	package com.meridian.retail.security;
2	
3	import jakarta.persistence.AttributeConverter;
4	import jakarta.persistence.Converter;
5	
6	/**
7	 * Transparent at-rest encryption for String entity fields. Apply with:
8	 *
9	 *   @Convert(converter = EncryptedStringConverter.class)
10	 *   @Column(columnDefinition = "TEXT")
11	 *   private String sensitiveField;
12	 *
13	 * The column must be TEXT (or at least VARCHAR(512+)) to hold the Base64 ciphertext,
14	 * which is ~33% larger than the plaintext plus overhead for the IV/GCM tag.
15	 *
16	 * NOTE: Hibernate instantiates converters before Spring is fully ready in some startup
17	 * paths, so we resolve the EncryptionService lazily via {@link EncryptionService#instance()}
18	 * rather than injecting it. A @PostConstruct in EncryptionService publishes the singleton.
19	 */
20	@Converter
21	public class EncryptedStringConverter implements AttributeConverter<String, String> {
22	
23	    @Override
24	    public String convertToDatabaseColumn(String attribute) {
25	        if (attribute == null) return null;
26	        return EncryptionService.instance().encrypt(attribute);
27	    }
28	
29	    @Override
30	    public String convertToEntityAttribute(String dbData) {
31	        if (dbData == null) return null;
32	        return EncryptionService.instance().decrypt(dbData);
33	    }
34	}
