1	package com.meridian.retail.security;
2	
3	import jakarta.annotation.PostConstruct;
4	import lombok.extern.slf4j.Slf4j;
5	import org.springframework.beans.factory.annotation.Value;
6	import org.springframework.stereotype.Service;
7	
8	import javax.crypto.Cipher;
9	import javax.crypto.SecretKey;
10	import javax.crypto.spec.GCMParameterSpec;
11	import javax.crypto.spec.SecretKeySpec;
12	import java.nio.charset.StandardCharsets;
13	import java.security.MessageDigest;
14	import java.security.SecureRandom;
15	import java.util.Base64;
16	
17	/**
18	 * AES-256-GCM encryption for at-rest sensitive values (HIGH-risk fields on domain
19	 * entities). Key is sourced from {@code app.encryption.key} — normally supplied via
20	 * environment variable in docker-compose — and stretched to 256 bits via SHA-256.
21	 *
22	 * Output format (Base64 of a single byte blob):
23	 *   [ 12-byte IV ][ ciphertext || 16-byte GCM tag ]
24	 *
25	 * The IV is random per call, so encrypting the same plaintext twice produces different
26	 * ciphertext — a property asserted by EncryptionServiceTest. A ciphertext produced on
27	 * one JVM can be decrypted by any other JVM sharing the same master key.
28	 *
29	 * We expose a static accessor ({@link #instance()}) because JPA AttributeConverters
30	 * are instantiated by the persistence provider, not Spring, and cannot receive
31	 * constructor injection. EncryptedStringConverter pulls the Spring-managed bean via
32	 * this holder after Spring starts.
33	 */
34	@Service
35	@Slf4j
36	public class EncryptionService {
37	
38	    private static final String ALGORITHM = "AES";
39	    private static final String TRANSFORM = "AES/GCM/NoPadding";
40	    private static final int IV_LENGTH_BYTES = 12;
41	    private static final int GCM_TAG_LENGTH_BITS = 128;
42	
43	    private static volatile EncryptionService INSTANCE;
44	
45	    private final SecretKey secretKey;
46	    private final SecureRandom random = new SecureRandom();
47	
48	    public EncryptionService(@Value("${app.encryption.key:retail-campaign-aes-key-32chars!!}") String rawKey) {
49	        if (rawKey == null || rawKey.isBlank()) {
50	            throw new IllegalStateException(
51	                    "app.encryption.key is required for EncryptionService — supply it via the ENCRYPTION_KEY env var");
52	        }
53	        try {
54	            // SHA-256 stretches any input to a 256-bit AES key. This is NOT a password-based
55	            // KDF (no salt, no iterations) — the raw key is expected to already be high-entropy,
56	            // stored in a secret manager / env var. SHA-256 is used only to normalize the length.
57	            byte[] digest = MessageDigest.getInstance("SHA-256").digest(rawKey.getBytes(StandardCharsets.UTF_8));
58	            this.secretKey = new SecretKeySpec(digest, ALGORITHM);
59	        } catch (Exception e) {
60	            throw new IllegalStateException("Failed to derive AES key", e);
61	        }
62	    }
63	
64	    @PostConstruct
65	    void publishInstance() {
66	        INSTANCE = this;
67	    }
68	
69	    /** Static accessor used by EncryptedStringConverter (see class-level javadoc). */
70	    public static EncryptionService instance() {
71	        EncryptionService ref = INSTANCE;
72	        if (ref == null) {
73	            throw new IllegalStateException(
74	                    "EncryptionService not initialized — called from outside Spring context?");
75	        }
76	        return ref;
77	    }
78	
79	    /**
80	     * Encrypt a UTF-8 string. Returns Base64(IV || ciphertext || tag). Returns null for
81	     * null input so @Column(nullable=true) fields survive the round-trip.
82	     */
83	    public String encrypt(String plaintext) {
84	        if (plaintext == null) return null;
85	        try {
86	            byte[] iv = new byte[IV_LENGTH_BYTES];
87	            random.nextBytes(iv);
88	            Cipher cipher = Cipher.getInstance(TRANSFORM);
89	            cipher.init(Cipher.ENCRYPT_MODE, secretKey, new GCMParameterSpec(GCM_TAG_LENGTH_BITS, iv));
90	            byte[] ct = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));
91	            byte[] out = new byte[iv.length + ct.length];
92	            System.arraycopy(iv, 0, out, 0, iv.length);
93	            System.arraycopy(ct, 0, out, iv.length, ct.length);
94	            return Base64.getEncoder().encodeToString(out);
95	        } catch (Exception e) {
96	            log.error("Encryption failed", e);
97	            throw new IllegalStateException("Encryption failed", e);
98	        }
99	    }
100	
101	    /**
102	     * Decrypt a value previously returned by {@link #encrypt(String)}. Returns null for
103	     * null input. Throws if the ciphertext is tampered, truncated, or authenticated with
104	     * a different key (GCM integrity check).
105	     */
106	    public String decrypt(String ciphertext) {
107	        if (ciphertext == null) return null;
108	        try {
109	            byte[] blob = Base64.getDecoder().decode(ciphertext);
110	            if (blob.length < IV_LENGTH_BYTES + 16) {
111	                throw new IllegalArgumentException("Ciphertext too short to contain IV + tag");
112	            }
113	            byte[] iv = new byte[IV_LENGTH_BYTES];
114	            System.arraycopy(blob, 0, iv, 0, IV_LENGTH_BYTES);
115	            byte[] ct = new byte[blob.length - IV_LENGTH_BYTES];
116	            System.arraycopy(blob, IV_LENGTH_BYTES, ct, 0, ct.length);
117	            Cipher cipher = Cipher.getInstance(TRANSFORM);
118	            cipher.init(Cipher.DECRYPT_MODE, secretKey, new GCMParameterSpec(GCM_TAG_LENGTH_BITS, iv));
119	            byte[] pt = cipher.doFinal(ct);
120	            return new String(pt, StandardCharsets.UTF_8);
121	        } catch (Exception e) {
122	            log.error("Decryption failed", e);
123	            throw new IllegalStateException("Decryption failed — ciphertext tampered or wrong key", e);
124	        }
125	    }
126	}
