1	package com.meridian.retail.config;
2	
3	import com.meridian.retail.security.CustomAuthenticationFailureHandler;
4	import com.meridian.retail.security.CustomAuthenticationSuccessHandler;
5	import com.meridian.retail.security.NonceValidationFilter;
6	import com.meridian.retail.security.PreAuthLockoutFilter;
7	import com.meridian.retail.security.RateLimitFilter;
8	import com.meridian.retail.security.RequestSigningFilter;
9	import com.meridian.retail.security.UserDetailsServiceImpl;
10	import lombok.RequiredArgsConstructor;
11	import org.springframework.context.annotation.Bean;
12	import org.springframework.context.annotation.Configuration;
13	import org.springframework.security.authentication.AuthenticationManager;
14	import org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilder;
15	import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
16	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
17	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
18	import org.springframework.security.config.http.SessionCreationPolicy;
19	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
20	import org.springframework.security.crypto.password.PasswordEncoder;
21	import org.springframework.security.web.SecurityFilterChain;
22	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
23	import org.springframework.security.web.csrf.CookieCsrfTokenRepository;
24	
25	/**
26	 * Spring Security configuration.
27	 *
28	 * Form-login (local username/password only — SPEC.md). All POST forms are CSRF-protected
29	 * via Spring Security's standard mechanism. Three custom filters are inserted BEFORE
30	 * UsernamePasswordAuthenticationFilter:
31	 *
32	 *   1. RateLimitFilter        — 60/min standard, 10/min export, per authenticated user
33	 *   2. NonceValidationFilter  — anti-replay for /admin/** and /approval/dual-approve/**
34	 *   3. RequestSigningFilter   — HMAC-SHA256 signature check for /admin/**
35	 *
36	 * Permit-all is intentionally narrow: only the login page, the locally-rendered CAPTCHA
37	 * image endpoint, the /actuator/health probe, and bundled vendor static assets.
38	 *
39	 * BCryptPasswordEncoder strength=12 matches the seed-data hashes in V12__seed_data.sql.
40	 */
41	@Configuration
42	@EnableWebSecurity
43	@EnableMethodSecurity
44	@RequiredArgsConstructor
45	public class SecurityConfig {
46	
47	    private final UserDetailsServiceImpl userDetailsService;
48	    private final CustomAuthenticationFailureHandler failureHandler;
49	    private final CustomAuthenticationSuccessHandler successHandler;
50	    private final RateLimitFilter rateLimitFilter;
51	    private final NonceValidationFilter nonceValidationFilter;
52	    private final RequestSigningFilter requestSigningFilter;
53	    private final PreAuthLockoutFilter preAuthLockoutFilter;
54	
55	    @Bean
56	    public PasswordEncoder passwordEncoder() {
57	        // strength = 12 matches the seed-data hashes; do not lower without re-seeding.
58	        return new BCryptPasswordEncoder(12);
59	    }
60	
61	    @Bean
62	    public AuthenticationManager authenticationManager(HttpSecurity http) throws Exception {
63	        AuthenticationManagerBuilder b = http.getSharedObject(AuthenticationManagerBuilder.class);
64	        b.userDetailsService(userDetailsService).passwordEncoder(passwordEncoder());
65	        return b.build();
66	    }
67	
68	    @Bean
69	    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
70	        http
71	            .csrf(csrf -> csrf
72	                // CSRF cookie is readable by JS so HTMX can include the token header.
73	                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
74	            )
75	            .authorizeHttpRequests(auth -> auth
76	                // Public surface — kept intentionally minimal.
77	                .requestMatchers("/login", "/captcha/**", "/health", "/actuator/health",
78	                                 "/css/**", "/js/**", "/vendor/**", "/error/**").permitAll()
79	                // Role-restricted areas.
80	                .requestMatchers("/admin/**").hasRole("ADMIN")
81	                .requestMatchers("/approval/**").hasAnyRole("ADMIN", "REVIEWER")
82	                .requestMatchers("/analytics/export/**").hasAnyRole("ADMIN", "FINANCE")
83	                .anyRequest().authenticated()
84	            )
85	            .formLogin(form -> form
86	                .loginPage("/login")
87	                .loginProcessingUrl("/login")
88	                .successHandler(successHandler)
89	                .failureHandler(failureHandler)
90	                .permitAll()
91	            )
92	            .logout(logout -> logout
93	                .logoutUrl("/logout")
94	                .logoutSuccessUrl("/login?logout")
95	                .invalidateHttpSession(true)
96	                .deleteCookies("JSESSIONID", "XSRF-TOKEN")
97	                .permitAll()
98	            )
99	            .sessionManagement(session -> session
100	                .sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED)
101	                .maximumSessions(3)   // allow a few concurrent sessions per user
102	            )
103	            // No explicit accessDeniedPage. Spring Security's default access-denied handler
104	            // sets HTTP 403 and forwards to /error, where Spring Boot's BasicErrorController
105	            // automatically selects templates/error/403.html based on the status code.
106	            // (accessDeniedPage("/error/403") was removed because it does a literal URL
107	            // forward — and there is no controller mapping for /error/403, so the dispatch
108	            // would fall through to the static-resource handler and return a confusing 404.)
109	            ;
110	
111	        // Custom filters in order. Rate limit runs first so an attacker hammering /login
112	        // gets throttled before any heavy work; nonce validation runs before signing so
113	        // we don't waste time computing HMAC for replays.
114	        http.addFilterBefore(rateLimitFilter, UsernamePasswordAuthenticationFilter.class);
115	        http.addFilterBefore(nonceValidationFilter, UsernamePasswordAuthenticationFilter.class);
116	        http.addFilterBefore(requestSigningFilter, UsernamePasswordAuthenticationFilter.class);
117	        // PreAuthLockoutFilter must sit directly in front of auth so a locked/CAPTCHA-
118	        // challenged account cannot bypass the brute-force controls by guessing the
119	        // password correctly. Placed last so it runs immediately before the auth filter.
120	        http.addFilterBefore(preAuthLockoutFilter, UsernamePasswordAuthenticationFilter.class);
121	
122	        return http.build();
123	    }
124	}
