<!-- R4 HIGH #1: anti-replay nonce on the actual dual-approval completion endpoints.
     Forms tagged .js-nonce-form intercept their submit, fetch a fresh nonce from
     /approval/nonce, and POST the form-encoded payload with X-Nonce + X-Timestamp
     headers so NonceValidationFilter can persist the nonce and reject any replay.
     The Reject buttons set data-skip-nonce so they fall through to a normal POST
     (Reject doesn't change campaign state to APPROVED, so it doesn't need the
     additional anti-replay protection — CSRF + role + audit log already cover it). -->
<script th:inline="none">
(function () {
    function csrfHeader() {
        var match = document.cookie.match(/(?:^|;\s*)XSRF-TOKEN=([^;]+)/);
        return match ? decodeURIComponent(match[1]) : '';
    }

    function fetchNonce() {
        return fetch('/approval/nonce', {
            method: 'GET',
            credentials: 'same-origin',
            headers: { 'Accept': 'application/json' }
        }).then(function (r) {
            if (!r.ok) throw new Error('nonce fetch failed: ' + r.status);
            return r.json();
        });
    }

    document.querySelectorAll('form.js-nonce-form').forEach(function (form) {
        // Track which submit button initiated the request so a Reject click is
        // routed to the configured formaction without going through the nonce flow.
        var lastSubmitter = null;
        form.querySelectorAll('button[type=submit]').forEach(function (btn) {
            btn.addEventListener('click', function () { lastSubmitter = btn; });
        });

        form.addEventListener('submit', function (ev) {
            if (lastSubmitter && lastSubmitter.getAttribute('data-skip-nonce') === 'true') {
                return; // normal browser POST
            }
            ev.preventDefault();
            var action = form.getAttribute('action');
            var data = new URLSearchParams(new FormData(form));
            fetchNonce().then(function (n) {
                return fetch(action, {
                    method: 'POST',
                    credentials: 'same-origin',
                    headers: {
                        'Content-Type': 'application/x-www-form-urlencoded',
                        'X-Nonce': n.nonce,
                        'X-Timestamp': String(n.timestamp),
                        'X-XSRF-TOKEN': csrfHeader()
                    },
                    body: data.toString(),
                    redirect: 'follow'
                });
            }).then(function (resp) {
                if (resp.redirected) {
                    window.location.href = resp.url;
                } else if (resp.ok) {
                    window.location.reload();
                } else {
                    return resp.text().then(function (t) {
                        alert('Approval failed (' + resp.status + '): ' + t);
                    });
                }
            }).catch(function (err) {
                alert('Approval request error: ' + err.message);
            });
        });
    });
})();
</script>
</body>
</html>"}

