{"file_path": "/home/abdelah/Documents/eaglepoint/TASK-31/repo/src/main/resources/static/js/nonce-form.js", "content": "/*
 * Browser anti-replay nonce injection.
 *
 * R4 audit HIGH #1 + HIGH #2: NonceValidationFilter no longer carries a blanket
 * application/x-www-form-urlencoded bypass for /admin/** or /approval/{id}/approve-*.
 * Privileged browser POSTs must therefore carry a valid nonce. Rather than rewriting
 * every admin form to be HTMX/fetch-driven (which would lose Spring's RedirectAttributes
 * flash messages), this script intercepts the form submit, fetches a fresh nonce from
 * the appropriate /admin/nonce or /approval/nonce endpoint, injects _nonce and
 * _timestamp as hidden fields, and lets the browser perform a normal POST.
 *
 * NonceValidationFilter accepts the nonce from EITHER the X-Nonce header (programmatic
 * clients) OR the _nonce form parameter (browser forms enriched here), so a normal
 * form POST is now functionally equivalent to a signed API call from a replay-protection
 * standpoint.
 *
 * Behaviour:
 *   - Auto-arms any <form method="post"> whose action starts with /admin/ or
 *     /approval/{id}/approve-first|second.
 *   - Skips forms that have data-skip-nonce="true" (e.g. logout, simple search).
 *   - Skips submit buttons that have data-skip-nonce="true" (e.g. Reject buttons that
 *     don't change campaign state to APPROVED).
 *   - Skips logout (handled by Spring Security separately and unaffected by this filter).
 */
(function () {
    function nonceEndpointFor(action) {
        if (action.indexOf('/admin/') === 0) return '/admin/nonce';
        if (action.indexOf('/approval/') === 0) return '/approval/nonce';
        return null;
    }

    function needsNonce(form) {
        if (form.method && form.method.toLowerCase() !== 'post') return false;
        if (form.dataset.skipNonce === 'true') return false;
        var action = form.getAttribute('action') || window.location.pathname;
        if (action.indexOf('/logout') === 0) return false;
        if (action.indexOf('/admin/') === 0) return true;
        if (action.indexOf('/approval/') === 0
                && (action.indexOf('/approve-first') !== -1
                    || action.indexOf('/approve-second') !== -1)) {
            return true;
        }
        return false;
    }

    function fetchNonce(endpoint) {
        return fetch(endpoint, {
            method: 'GET',
            credentials: 'same-origin',
            headers: { 'Accept': 'application/json' }
        }).then(function (r) {
            if (!r.ok) throw new Error('nonce fetch failed: ' + r.status);
            return r.json();
        });
    }

    function setHidden(form, name, value) {
        var input = form.querySelector('input[type=hidden][name="' + name + '"]');
        if (!input) {
            input = document.createElement('input');
            input.type = 'hidden';
            input.name = name;
            form.appendChild(input);
        }
        input.value = value;
    }

    function arm(form) {
        if (form.dataset.nonceWired === 'true') return;
        form.dataset.nonceWired = 'true';

        var lastSubmitter = null;
        form.querySelectorAll('button[type=submit], input[type=submit]').forEach(function (btn) {
            btn.addEventListener('click', function () { lastSubmitter = btn; });
        });

        form.addEventListener('submit', function (ev) {
            if (lastSubmitter && lastSubmitter.getAttribute('data-skip-nonce') === 'true') {
                return;
            }
            // Use the button's formaction (if set) over the form action so Reject /
            // alternative submit buttons get scoped correctly.
            var action = (lastSubmitter && lastSubmitter.getAttribute('formaction'))
                    || form.getAttribute('action')
                    || window.location.pathname;
            if (form.dataset.nonceArmed === 'true') return;

            var endpoint = nonceEndpointFor(action);
            if (!endpoint) return; // not a privileged path — let the browser submit normally

            ev.preventDefault();
            fetchNonce(endpoint).then(function (n) {
                setHidden(form, '_nonce', n.nonce);
                setHidden(form, '_timestamp', String(n.timestamp));
                form.dataset.nonceArmed = 'true';
                if (lastSubmitter) {
                    lastSubmitter.click();
                } else {
                    form.submit();
                }
            }).catch(function (err) {
                alert('Could not fetch anti-replay nonce: ' + err.message);
            });
        });
    }

    function scan(root) {
        (root || document).querySelectorAll('form').forEach(function (form) {
            if (needsNonce(form)) arm(form);
        });
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', function () { scan(document); });
    } else {
        scan(document);
    }
})();
"}

