1	package com.meridian.retail.security;
2	
3	import jakarta.servlet.FilterChain;
4	import org.junit.jupiter.api.Test;
5	import org.junit.jupiter.api.extension.ExtendWith;
6	import org.mockito.Mock;
7	import org.mockito.junit.jupiter.MockitoExtension;
8	import org.springframework.mock.web.MockHttpServletRequest;
9	import org.springframework.mock.web.MockHttpServletResponse;
10	import org.springframework.test.util.ReflectionTestUtils;
11	
12	import static org.mockito.Mockito.never;
13	import static org.mockito.Mockito.verify;
14	
15	/**
16	 * BLOCKER #1 regression: browser form POSTs to /admin/** must pass straight through
17	 * both the nonce filter AND the signing filter, because admin Thymeleaf forms have no
18	 * way to produce X-Nonce / X-Signature / X-Timestamp headers and are already protected
19	 * by CSRF + session auth + RBAC. Only JSON / programmatic callers should be subjected
20	 * to the anti-replay + signing checks.
21	 */
22	@ExtendWith(MockitoExtension.class)
23	class AdminFilterBypassTest {
24	
25	    @Mock FilterChain chain;
26	
27	    @Test
28	    void nonceFilterSkipsAdminFormPost() throws Exception {
29	        NonceValidationFilter f = new NonceValidationFilter(null);
30	        MockHttpServletRequest req = new MockHttpServletRequest();
31	        req.setMethod("POST");
32	        req.setRequestURI("/admin/users");
33	        req.setContentType("application/x-www-form-urlencoded");
34	        MockHttpServletResponse res = new MockHttpServletResponse();
35	
36	        f.doFilter(req, res, chain);
37	
38	        // No 400 (missing header), chain was invoked normally.
39	        verify(chain).doFilter(req, res);
40	    }
41	
42	    @Test
43	    void signingFilterSkipsAdminFormPost() throws Exception {
44	        RequestSigningFilter f = new RequestSigningFilter();
45	        ReflectionTestUtils.setField(f, "signingSecret", "retail-campaign-hmac-signing-key!!");
46	        MockHttpServletRequest req = new MockHttpServletRequest();
47	        req.setMethod("POST");
48	        req.setRequestURI("/admin/users");
49	        req.setContentType("application/x-www-form-urlencoded");
50	        MockHttpServletResponse res = new MockHttpServletResponse();
51	
52	        f.doFilter(req, res, chain);
53	
54	        verify(chain).doFilter(req, res);
55	    }
56	
57	    /** R3 tightening: multipart/form-data under /admin/** must NOT be exempt. */
58	    @Test
59	    void signingFilterRejectsAdminMultipartWithoutSignature() throws Exception {
60	        RequestSigningFilter f = new RequestSigningFilter();
61	        ReflectionTestUtils.setField(f, "signingSecret", "retail-campaign-hmac-signing-key!!");
62	        MockHttpServletRequest req = new MockHttpServletRequest();
63	        req.setMethod("POST");
64	        req.setRequestURI("/admin/users");
65	        req.setContentType("multipart/form-data; boundary=xxx");
66	        MockHttpServletResponse res = new MockHttpServletResponse();
67	
68	        f.doFilter(req, res, chain);
69	
70	        verify(chain, never()).doFilter(req, res);
71	    }
72	
73	    /** R3 tightening: multipart/form-data under /admin/** must NOT be exempt from nonce either. */
74	    @Test
75	    void nonceFilterRejectsAdminMultipartWithoutHeaders() throws Exception {
76	        NonceValidationFilter f = new NonceValidationFilter(null);
77	        MockHttpServletRequest req = new MockHttpServletRequest();
78	        req.setMethod("POST");
79	        req.setRequestURI("/admin/users");
80	        req.setContentType("multipart/form-data; boundary=xxx");
81	        MockHttpServletResponse res = new MockHttpServletResponse();
82	
83	        f.doFilter(req, res, chain);
84	
85	        verify(chain, never()).doFilter(req, res);
86	    }
87	
88	    @Test
89	    void nonceFilterStillRejectsAdminJsonWithoutHeaders() throws Exception {
90	        NonceValidationFilter f = new NonceValidationFilter(null);
91	        MockHttpServletRequest req = new MockHttpServletRequest();
92	        req.setMethod("POST");
93	        req.setRequestURI("/admin/api/something");
94	        req.setContentType("application/json");
95	        MockHttpServletResponse res = new MockHttpServletResponse();
96	
97	        f.doFilter(req, res, chain);
98	
99	        // JSON callers must still be blocked without a nonce. Chain NOT invoked.
100	        verify(chain, never()).doFilter(req, res);
101	    }
102	}
