3	import com.meridian.retail.entity.UsedNonce;
4	import com.meridian.retail.repository.UsedNonceRepository;
5	import jakarta.servlet.FilterChain;
6	import org.junit.jupiter.api.Test;
7	import org.junit.jupiter.api.extension.ExtendWith;
8	import org.mockito.Mock;
9	import org.mockito.junit.jupiter.MockitoExtension;
10	import org.springframework.mock.web.MockHttpServletRequest;
11	import org.springframework.mock.web.MockHttpServletResponse;
12	import org.springframework.test.util.ReflectionTestUtils;
13	
14	import javax.crypto.Mac;
15	import javax.crypto.spec.SecretKeySpec;
16	import java.nio.charset.StandardCharsets;
17	import java.security.MessageDigest;
18	import java.util.HexFormat;
19	
20	import static org.mockito.Mockito.never;
21	import static org.mockito.Mockito.verify;
22	import static org.mockito.Mockito.when;
23	
24	/**
25	 * MEDIUM #7: positive + negative matrix for the anti-replay + signing filters on a
26	 * privileged JSON POST under /admin/**.
27	 *
28	 * Scenarios:
29	 *   1. Valid nonce + timestamp + signature            -> passes
30	 *   2. Missing X-Nonce                                 -> rejected
31	 *   3. Invalid X-Signature                             -> rejected
32	 *   4. Replayed nonce (already in used_nonces)         -> rejected
33	 *   5. Expired timestamp (outside ±5 min window)       -> rejected
34	 *
35	 * The tests run the filters directly rather than through MockMvc so we don't need a full
36	 * Spring context or a MySQL dependency.
37	 */
38	@ExtendWith(MockitoExtension.class)
39	class NonceSignatureMatrixTest {
40	
41	    private static final String SIGNING_KEY = "retail-campaign-hmac-signing-key!!";
42	
43	    @Mock UsedNonceRepository usedNonceRepository;
44	    @Mock FilterChain chain;
45	
46	    private MockHttpServletRequest jsonAdminPost(String nonce, String timestamp,
47	                                                 String signature, String body) {
48	        MockHttpServletRequest req = new MockHttpServletRequest("POST", "/admin/api/secret");
49	        req.setContentType("application/json");
50	        if (nonce != null) req.addHeader("X-Nonce", nonce);
51	        if (timestamp != null) req.addHeader("X-Timestamp", timestamp);
52	        if (signature != null) req.addHeader("X-Signature", signature);
53	        req.setContent(body.getBytes(StandardCharsets.UTF_8));
54	        return req;
55	    }
56	
57	    private String hmacSha256Hex(String data) {
58	        try {
59	            Mac mac = Mac.getInstance("HmacSHA256");
60	            mac.init(new SecretKeySpec(SIGNING_KEY.getBytes(StandardCharsets.UTF_8), "HmacSHA256"));
61	            return HexFormat.of().formatHex(mac.doFinal(data.getBytes(StandardCharsets.UTF_8)));
62	        } catch (Exception e) {
63	            throw new RuntimeException(e);
64	        }
65	    }
66	
67	    private String sha256Hex(byte[] data) {
68	        try {
69	            return HexFormat.of().formatHex(MessageDigest.getInstance("SHA-256").digest(data));
70	        } catch (Exception e) {
71	            throw new RuntimeException(e);
72	        }
73	    }
74	
75	    private RequestSigningFilter signingFilter() {
76	        RequestSigningFilter f = new RequestSigningFilter();
77	        ReflectionTestUtils.setField(f, "signingSecret", SIGNING_KEY);
78	        return f;
79	    }
80	
81	    @Test
82	    void validRequestPassesBothFilters() throws Exception {
83	        String nonce = "nonce-abc-123";
84	        String timestamp = String.valueOf(System.currentTimeMillis());
85	        String body = "{\"x\":1}";
86	        String canonical = "POST\n/admin/api/secret\n" + timestamp + "\n" + sha256Hex(body.getBytes());
87	        String signature = hmacSha256Hex(canonical);
88	
89	        when(usedNonceRepository.existsByNonce(nonce)).thenReturn(false);
90	
91	        NonceValidationFilter nonceF = new NonceValidationFilter(usedNonceRepository);
92	        MockHttpServletRequest req1 = jsonAdminPost(nonce, timestamp, signature, body);
93	        MockHttpServletResponse res1 = new MockHttpServletResponse();
94	        nonceF.doFilter(req1, res1, chain);
95	        verify(chain).doFilter(req1, res1);
96	
97	        RequestSigningFilter signF = signingFilter();
98	        MockHttpServletRequest req2 = jsonAdminPost(nonce, timestamp, signature, body);
99	        MockHttpServletResponse res2 = new MockHttpServletResponse();
100	        signF.doFilter(req2, res2, chain);
101	        org.assertj.core.api.Assertions.assertThat(res2.getStatus()).isNotEqualTo(403);
102	    }
103	
104	    @Test
105	    void missingNonceIsRejected() throws Exception {
106	        NonceValidationFilter nonceF = new NonceValidationFilter(usedNonceRepository);
107	        MockHttpServletRequest req = jsonAdminPost(null, String.valueOf(System.currentTimeMillis()),
108	                "dummy", "{}");
109	        MockHttpServletResponse res = new MockHttpServletResponse();
110	
111	        nonceF.doFilter(req, res, chain);
112	
113	        org.assertj.core.api.Assertions.assertThat(res.getStatus()).isEqualTo(400);
114	        verify(chain, never()).doFilter(req, res);
115	    }
116	
117	    @Test
118	    void invalidSignatureIsRejected() throws Exception {
119	        String timestamp = String.valueOf(System.currentTimeMillis());
120	        String body = "{\"x\":1}";
