1	/*
2	 * Browser anti-replay nonce injection.
3	 *
4	 * R4 audit HIGH #1 + HIGH #2: NonceValidationFilter no longer carries a blanket
5	 * application/x-www-form-urlencoded bypass for /admin/** or /approval/{id}/approve-*.
6	 * Privileged browser POSTs must therefore carry a valid nonce. Rather than rewriting
7	 * every admin form to be HTMX/fetch-driven (which would lose Spring's RedirectAttributes
8	 * flash messages), this script intercepts the form submit, fetches a fresh nonce from
9	 * the appropriate /admin/nonce or /approval/nonce endpoint, injects _nonce and
10	 * _timestamp as hidden fields, and lets the browser perform a normal POST.
11	 *
12	 * NonceValidationFilter accepts the nonce from EITHER the X-Nonce header (programmatic
13	 * clients) OR the _nonce form parameter (browser forms enriched here), so a normal
14	 * form POST is now functionally equivalent to a signed API call from a replay-protection
15	 * standpoint.
16	 *
17	 * Behaviour:
18	 *   - Auto-arms any <form method="post"> whose action starts with /admin/ or
19	 *     /approval/{id}/approve-first|second.
20	 *   - Skips forms that have data-skip-nonce="true" (e.g. logout, simple search).
21	 *   - Skips submit buttons that have data-skip-nonce="true" (e.g. Reject buttons that
22	 *     don't change campaign state to APPROVED).
23	 *   - Skips logout (handled by Spring Security separately and unaffected by this filter).
24	 */
25	(function () {
26	    function nonceEndpointFor(action) {
27	        if (action.indexOf('/admin/') === 0) return '/admin/nonce';
28	        if (action.indexOf('/approval/') === 0) return '/approval/nonce';
29	        return null;
30	    }
31	
32	    function needsNonce(form) {
33	        if (form.method && form.method.toLowerCase() !== 'post') return false;
34	        if (form.dataset.skipNonce === 'true') return false;
35	        var action = form.getAttribute('action') || window.location.pathname;
36	        if (action.indexOf('/logout') === 0) return false;
37	        if (action.indexOf('/admin/') === 0) return true;
38	        if (action.indexOf('/approval/') === 0
39	                && (action.indexOf('/approve-first') !== -1
40	                    || action.indexOf('/approve-second') !== -1
41	                    || action.indexOf('/dual-approve/') !== -1)) {
42	            return true;
43	        }
44	        return false;
45	    }
46	
47	    function fetchNonce(endpoint) {
48	        return fetch(endpoint, {
49	            method: 'GET',
50	            credentials: 'same-origin',
51	            headers: { 'Accept': 'application/json' }
52	        }).then(function (r) {
53	            if (!r.ok) throw new Error('nonce fetch failed: ' + r.status);
54	            return r.json();
55	        });
56	    }
57	
58	    function setHidden(form, name, value) {
59	        var input = form.querySelector('input[type=hidden][name="' + name + '"]');
60	        if (!input) {
61	            input = document.createElement('input');
62	            input.type = 'hidden';
63	            input.name = name;
64	            form.appendChild(input);
65	        }
66	        input.value = value;
67	    }
68	
69	    function arm(form) {
70	        if (form.dataset.nonceWired === 'true') return;
71	        form.dataset.nonceWired = 'true';
72	
73	        var lastSubmitter = null;
74	        form.querySelectorAll('button[type=submit], input[type=submit]').forEach(function (btn) {
75	            btn.addEventListener('click', function () { lastSubmitter = btn; });
76	        });
77	
78	        form.addEventListener('submit', function (ev) {
79	            if (lastSubmitter && lastSubmitter.getAttribute('data-skip-nonce') === 'true') {
80	                return;
81	            }
82	            // Use the button's formaction (if set) over the form action so Reject /
83	            // alternative submit buttons get scoped correctly.
84	            var action = (lastSubmitter && lastSubmitter.getAttribute('formaction'))
85	                    || form.getAttribute('action')
86	                    || window.location.pathname;
