12	
13	import static org.mockito.Mockito.never;
14	import static org.mockito.Mockito.verify;
15	import static org.mockito.Mockito.when;
16	
17	/**
18	 * R4 HIGH #1 + #2: NonceValidationFilter no longer carries a blanket form-encoded
19	 * bypass for /admin/**. Browser form POSTs must include _nonce / _timestamp hidden
20	 * fields (injected by static/js/nonce-form.js). RequestSigningFilter still has the
21	 * form-encoded bypass because HMAC signing requires a shared secret that cannot live
22	 * in the browser — see SecurityDesignDecisions.md.
23	 */
24	@ExtendWith(MockitoExtension.class)
25	class AdminFilterBypassTest {
26	
27	    @Mock FilterChain chain;
28	    @Mock UsedNonceRepository usedNonceRepository;
29	
30	    @Test
31	    void nonceFilterRejectsAdminFormPostWithoutNonce() throws Exception {
32	        // R4 HIGH #2: blanket form-encoded bypass removed. A form POST to /admin/**
33	        // without _nonce/_timestamp must now be rejected.
34	        NonceValidationFilter f = new NonceValidationFilter(usedNonceRepository);
35	        MockHttpServletRequest req = new MockHttpServletRequest();
36	        req.setMethod("POST");
37	        req.setRequestURI("/admin/users");
38	        req.setContentType("application/x-www-form-urlencoded");
39	        MockHttpServletResponse res = new MockHttpServletResponse();
40	
41	        f.doFilter(req, res, chain);
42	
43	        org.assertj.core.api.Assertions.assertThat(res.getStatus()).isEqualTo(400);
44	        verify(chain, never()).doFilter(req, res);
45	    }
46	
47	    @Test
48	    void nonceFilterAcceptsAdminFormPostWithNonceFormFields() throws Exception {
49	        // The browser-friendly path: hidden _nonce + _timestamp form params satisfy the
50	        // anti-replay check (no header required).
51	        when(usedNonceRepository.existsByNonce("nonce-form-1")).thenReturn(false);
52	        NonceValidationFilter f = new NonceValidationFilter(usedNonceRepository);
53	        MockHttpServletRequest req = new MockHttpServletRequest();
54	        req.setMethod("POST");
55	        req.setRequestURI("/admin/users");
56	        req.setContentType("application/x-www-form-urlencoded");
57	        req.setParameter("_nonce", "nonce-form-1");
58	        req.setParameter("_timestamp", String.valueOf(System.currentTimeMillis()));
59	        MockHttpServletResponse res = new MockHttpServletResponse();
60	
61	        f.doFilter(req, res, chain);
62	
63	        verify(chain).doFilter(req, res);
64	    }
65	
66	    @Test
67	    void signingFilterSkipsAdminFormPost() throws Exception {
68	        RequestSigningFilter f = new RequestSigningFilter();
69	        ReflectionTestUtils.setField(f, "signingSecret", "retail-campaign-hmac-signing-key!!");
70	        MockHttpServletRequest req = new MockHttpServletRequest();
71	        req.setMethod("POST");
72	        req.setRequestURI("/admin/users");
73	        req.setContentType("application/x-www-form-urlencoded");
74	        MockHttpServletResponse res = new MockHttpServletResponse();
75	
76	        f.doFilter(req, res, chain);
77	
78	        verify(chain).doFilter(req, res);
79	    }
80	
81	    /** R3 tightening: multipart/form-data under /admin/** must NOT be exempt. */
82	    @Test
83	    void signingFilterRejectsAdminMultipartWithoutSignature() throws Exception {
84	        RequestSigningFilter f = new RequestSigningFilter();
85	        ReflectionTestUtils.setField(f, "signingSecret", "retail-campaign-hmac-signing-key!!");
86	        MockHttpServletRequest req = new MockHttpServletRequest();
87	        req.setMethod("POST");
88	        req.setRequestURI("/admin/users");
89	        req.setContentType("multipart/form-data; boundary=xxx");
90	        MockHttpServletResponse res = new MockHttpServletResponse();
91	
92	        f.doFilter(req, res, chain);
93	
94	        verify(chain, never()).doFilter(req, res);
95	    }
96	
97	    /** R3 tightening: multipart/form-data under /admin/** must NOT be exempt from nonce either. */
98	    @Test
99	    void nonceFilterRejectsAdminMultipartWithoutHeaders() throws Exception {
100	        NonceValidationFilter f = new NonceValidationFilter(null);
101	        MockHttpServletRequest req = new MockHttpServletRequest();
102	        req.setMethod("POST");
103	        req.setRequestURI("/admin/users");
104	        req.setContentType("multipart/form-data; boundary=xxx");
105	        MockHttpServletResponse res = new MockHttpServletResponse();
106	
107	        f.doFilter(req, res, chain);
108	
109	        verify(chain, never()).doFilter(req, res);
110	    }
111	
112	    @Test
113	    void nonceFilterStillRejectsAdminJsonWithoutHeaders() throws Exception {
114	        NonceValidationFilter f = new NonceValidationFilter(null);
115	        MockHttpServletRequest req = new MockHttpServletRequest();
116	        req.setMethod("POST");
117	        req.setRequestURI("/admin/api/something");
118	        req.setContentType("application/json");
119	        MockHttpServletResponse res = new MockHttpServletResponse();
